/// Looks up the binary published for a driver on a given target, if there is one.
///
/// Pico do not build every driver for every target, so `None` here means the driver is
/// genuinely unavailable rather than that something went wrong.
pub fn lookup(driver: Driver, os: &str, arch: &str) -> Option<&'static DriverBinary> {
    BINARIES
        .iter()
        .find(|b| b.driver == driver && b.os == os && b.arch == arch)
}
